import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const pkgRoot = join(__dirname, "..");
const tsLibDir = join(pkgRoot, "node_modules", "typescript", "lib");
const outFile = join(pkgRoot, "src", "compiler", "lib-dts.generated.ts");

const libFiles = ["lib.es5.d.ts", "lib.decorators.d.ts", "lib.decorators.legacy.d.ts"];

function escapeForTemplateLiteral(str) {
  return str.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/\$\{/g, "\\${");
}

let output = "// Generated by scripts/bundle-lib-dts.js -- do not edit\n\n";
output += "export const LIB_FILES: Record<string, string> = {\n";

for (const name of libFiles) {
  const content = readFileSync(join(tsLibDir, name), "utf-8");
  const escaped = escapeForTemplateLiteral(content);
  output += `  ${JSON.stringify(name)}: \`${escaped}\`,\n`;
}

output += "};\n";

mkdirSync(dirname(outFile), { recursive: true });
writeFileSync(outFile, output, "utf-8");
